   278→async function main() {
   279→  try {
   280→    const input = await readStdinWithTimeout();
   281→    const data: HookInput = JSON.parse(input);
   282→    const prompt = data.prompt || data.user_prompt || '';
   283→    const sessionId = data.session_id || 'unknown';
