   286→        let agentType = null;
   287→        const agentMatch = taskOutput.match(/Sub-agent\s+(\w+)\s+completed/i);
   288→        if (agentMatch) {
   289→          agentType = agentMatch[1].toLowerCase();
   290→        }
   291→
   292→        return { message, agentType };
   293→      }
   294→    }
   295→  }
   296→
   297→  return { message: null, agentType: null };
