     1→/**
     2→ * SystemIntegrity.ts - Automatic system integrity maintenance handler
     3→ *
     4→ * Detects PAI system changes from the transcript and spawns background
     5→ * IntegrityMaintenance.ts to update references and document changes.
     6→ *
     7→ * TRIGGER: Stop hook (via StopOrchestrator)
     8→ *
     9→ * SIDE EFFECTS:
    10→ * - Spawns background IntegrityMaintenance.ts process
    11→ * - Voice notification on start
    12→ * - Updates MEMORY/STATE/integrity-state.json
    13→ *
    14→ * THROTTLING:
    15→ * - 5-minute cooldown between runs
    16→ * - Deduplicates identical change sets
    17→ */
    18→
    19→import { writeFileSync, mkdirSync, existsSync } from 'fs';
    20→import { spawn } from 'child_process';
    21→import { join } from 'path';
    22→import { paiPath } from '../lib/paths';
    23→import {
    24→  parseToolUseBlocks,
    25→  isSignificantChange,
    26→  isInCooldown,
    27→  isDuplicateRun,
    28→  hashChanges,
    29→  getCooldownEndTime,
    30→  determineSignificance,
    31→  inferChangeType,
    32→  generateDescriptiveTitle,
    33→  type FileChange,
    34→} from '../lib/change-detection';
    35→import type { ParsedTranscript } from '../../skills/PAI/Tools/TranscriptParser';
    36→
    37→interface HookInput {
    38→  session_id: string;
    39→  transcript_path: string;
    40→  hook_event_name: string;
    41→}
    42→
    43→const STATE_DIR = paiPath('MEMORY', 'STATE');
    44→const STATE_FILE = join(STATE_DIR, 'integrity-state.json');
    45→const INTEGRITY_SCRIPT = paiPath('skills', 'PAI', 'Tools', 'IntegrityMaintenance.ts');
    46→
    47→/**
    48→ * Send voice notification for integrity check start.
    49→ * Fire-and-forget - doesn't block.
    50→ * Uses ElevenLabs TTS via voice server.
    51→ * Includes 4-second delay to let main voice handler finish speaking first.
    52→ */
    53→async function notifyIntegrityStart(): Promise<void> {
    54→  try {
    55→    // Wait 4 seconds for main voice handler to finish speaking
    56→    await new Promise(resolve => setTimeout(resolve, 4000));
    57→
    58→    // Load identity for voice settings
    59→    const { getIdentity } = await import('../lib/identity');
    60→    const identity = getIdentity();
    61→
    62→    const voiceId = identity.voiceId || 's3TPKV1kjDlVtZbl4Ksh';
    63→    const voiceSettings = identity.voice;
    64→
    65→    await fetch('http://localhost:8888/notify', {
    66→      method: 'POST',
    67→      headers: { 'Content-Type': 'application/json' },
    68→      body: JSON.stringify({
    69→        message: 'Checking system integrity for recent changes.',
    70→        title: `${identity.name} says`,
    71→        voice_enabled: true,
    72→        voice_id: voiceId,
    73→        voice_settings: voiceSettings ? {
    74→          stability: voiceSettings.stability ?? 0.5,
    75→          similarity_boost: voiceSettings.similarity_boost ?? 0.75,
    76→          style: voiceSettings.style ?? 0.0,
    77→          speed: voiceSettings.speed ?? 1.0,
    78→          use_speaker_boost: voiceSettings.use_speaker_boost ?? true,
    79→        } : undefined,
    80→      }),
    81→    });
    82→  } catch {
    83→    // Voice server might not be running - silent fail
    84→  }
    85→}
    86→
    87→/**
    88→ * Update the integrity state file.
    89→ */
    90→function updateIntegrityState(changes: FileChange[]): void {
    91→  try {
    92→    if (!existsSync(STATE_DIR)) {
    93→      mkdirSync(STATE_DIR, { recursive: true });
    94→    }
    95→
    96→    const state = {
    97→      last_run: new Date().toISOString(),
    98→      last_changes_hash: hashChanges(changes),
    99→      cooldown_until: getCooldownEndTime(),
   100→    };
   101→
   102→    writeFileSync(STATE_FILE, JSON.stringify(state, null, 2));
   103→    console.error('[SystemIntegrity] Updated state file');
   104→  } catch (error) {
   105→    console.error('[SystemIntegrity] Failed to update state:', error);
   106→  }
   107→}
   108→
   109→/**
   110→ * Spawn the IntegrityMaintenance script in the background.
   111→ */
   112→function spawnIntegrityMaintenance(
   113→  changes: FileChange[],
   114→  hookInput: HookInput
   115→): void {
   116→  try {
   117→    // Check if script exists
   118→    if (!existsSync(INTEGRITY_SCRIPT)) {
   119→      console.error('[SystemIntegrity] IntegrityMaintenance.ts not found:', INTEGRITY_SCRIPT);
   120→      return;
   121→    }
   122→
   123→    // Pre-compute title and metadata for logging
   124→    const filteredChanges = changes.filter(c => c.category !== null);
   125→    const title = generateDescriptiveTitle(filteredChanges);
   126→    const significance = determineSignificance(filteredChanges);
   127→    const changeType = inferChangeType(filteredChanges);
   128→
   129→    console.error(`[SystemIntegrity] Title: ${title}`);
   130→    console.error(`[SystemIntegrity] Significance: ${significance}`);
   131→    console.error(`[SystemIntegrity] Change type: ${changeType}`);
   132→
   133→    // Prepare input data
   134→    const inputData = JSON.stringify({
   135→      session_id: hookInput.session_id,
   136→      transcript_path: hookInput.transcript_path,
   137→      changes: filteredChanges.map(c => ({
   138→        tool: c.tool,
   139→        path: c.path,
   140→        category: c.category,
   141→        isPhilosophical: c.isPhilosophical,
   142→        isStructural: c.isStructural,
   143→      })),
   144→    });
   145→
   146→    // Spawn detached process
   147→    const child = spawn('bun', [INTEGRITY_SCRIPT], {
   148→      detached: true,
   149→      stdio: ['pipe', 'ignore', 'inherit'],  // stdin for input, ignore stdout, inherit stderr for logging
   150→      env: { ...process.env },
   151→    });
   152→
   153→    // Write input data to stdin
   154→    child.stdin?.write(inputData);
   155→    child.stdin?.end();
   156→
   157→    // Detach from parent
   158→    child.unref();
   159→
   160→    console.error(`[SystemIntegrity] Spawned IntegrityMaintenance (pid: ${child.pid})`);
   161→  } catch (error) {
   162→    console.error('[SystemIntegrity] Failed to spawn IntegrityMaintenance:', error);
   163→  }
   164→}
   165→
   166→/**
   167→ * Handle system integrity check with pre-parsed transcript data.
   168→ *
   169→ * This handler:
   170→ * 1. Parses the transcript for file modification tool_use blocks
   171→ * 2. Filters for PAI system paths (excludes WORK/, LEARNING/, scratch/)
   172→ * 3. Checks throttle cooldown (max once per 5 min)
   173→ * 4. Spawns background IntegrityMaintenance.ts if changes detected
   174→ */
   175→export async function handleSystemIntegrity(
   176→  parsed: ParsedTranscript,
   177→  hookInput: HookInput
   178→): Promise<void> {
   179→  console.error('[SystemIntegrity] Checking for system changes...');
   180→
   181→  // Check cooldown
   182→  if (isInCooldown()) {
   183→    console.error('[SystemIntegrity] In cooldown period, skipping');
   184→    return;
   185→  }
   186→
   187→  // Parse changes from transcript
   188→  const changes = parseToolUseBlocks(hookInput.transcript_path);
   189→  console.error(`[SystemIntegrity] Found ${changes.length} file changes in transcript`);
   190→
   191→  // Filter to only PAI system changes
   192→  const systemChanges = changes.filter(c => c.category !== null);
   193→  console.error(`[SystemIntegrity] ${systemChanges.length} are PAI system changes`);
   194→
   195→  if (systemChanges.length === 0) {
   196→    console.error('[SystemIntegrity] No system changes detected, skipping');
   197→    return;
   198→  }
   199→
   200→  // Check if significant
   201→  if (!isSignificantChange(systemChanges)) {
   202→    console.error('[SystemIntegrity] Changes not significant enough, skipping');
   203→    return;
   204→  }
   205→
   206→  // Check for duplicate run
   207→  if (isDuplicateRun(changes)) {
   208→    console.error('[SystemIntegrity] Duplicate change set, skipping');
   209→    return;
   210→  }
   211→
   212→  // Log what we found
   213→  console.error('[SystemIntegrity] Significant changes detected:');
   214→  for (const change of systemChanges.slice(0, 5)) {
   215→    console.error(`  - [${change.category}] ${change.path}`);
   216→  }
   217→  if (systemChanges.length > 5) {
   218→    console.error(`  ... and ${systemChanges.length - 5} more`);
   219→  }
   220→
   221→  // Update state before spawning
   222→  updateIntegrityState(systemChanges);
   223→
   224→  // Send voice notification (fire-and-forget)
   225→  notifyIntegrityStart().catch(() => {});
   226→
   227→  // Spawn background process
   228→  spawnIntegrityMaintenance(systemChanges, hookInput);
   229→
   230→  console.error('[SystemIntegrity] Background integrity check started');
   231→}
