     1→/**
     2→ * Central Identity Loader
     3→ * Single source of truth for DA (Digital Assistant) and Principal identity
     4→ *
     5→ * Reads from settings.json - the programmatic way, not markdown parsing.
     6→ * All hooks and tools should import from here.
     7→ */
     8→
     9→import { readFileSync, existsSync } from 'fs';
    10→import { join } from 'path';
    11→
    12→const HOME = process.env.HOME!;
    13→const SETTINGS_PATH = join(HOME, '.claude/settings.json');
    14→
    15→// Default identity (fallback if settings.json doesn't have identity section)
    16→const DEFAULT_IDENTITY = {
    17→  name: 'PAI',
    18→  fullName: 'Personal AI',
    19→  displayName: 'PAI',
    20→  voiceId: '',
    21→  color: '#3B82F6',
    22→};
    23→
    24→const DEFAULT_PRINCIPAL = {
    25→  name: 'User',
    26→  pronunciation: '',
    27→  timezone: 'UTC',
    28→};
    29→
    30→export interface VoiceProsody {
    31→  stability: number;
    32→  similarity_boost: number;
    33→  style: number;
    34→  speed: number;
    35→  use_speaker_boost: boolean;
    36→}
    37→
    38→export interface VoicePersonality {
    39→  baseVoice: string;
    40→  enthusiasm: number;
    41→  energy: number;
    42→  expressiveness: number;
    43→  resilience: number;
    44→  composure: number;
    45→  optimism: number;
    46→  warmth: number;
    47→  formality: number;
    48→  directness: number;
    49→  precision: number;
    50→  curiosity: number;
    51→  playfulness: number;
    52→}
    53→
    54→export interface Identity {
    55→  name: string;
    56→  fullName: string;
    57→  displayName: string;
    58→  voiceId: string;
    59→  color: string;
    60→  voice?: VoiceProsody;
    61→  personality?: VoicePersonality;
    62→}
    63→
    64→export interface Principal {
    65→  name: string;
    66→  pronunciation: string;
    67→  timezone: string;
    68→}
    69→
    70→export interface Settings {
    71→  daidentity?: Partial<Identity>;
    72→  principal?: Partial<Principal>;
    73→  env?: Record<string, string>;
    74→  [key: string]: unknown;
    75→}
    76→
    77→let cachedSettings: Settings | null = null;
    78→
    79→/**
    80→ * Load settings.json (cached)
    81→ */
    82→function loadSettings(): Settings {
    83→  if (cachedSettings) return cachedSettings;
    84→
    85→  try {
    86→    if (!existsSync(SETTINGS_PATH)) {
    87→      cachedSettings = {};
    88→      return cachedSettings;
    89→    }
    90→
    91→    const content = readFileSync(SETTINGS_PATH, 'utf-8');
    92→    cachedSettings = JSON.parse(content);
    93→    return cachedSettings!;
    94→  } catch {
    95→    cachedSettings = {};
    96→    return cachedSettings;
    97→  }
    98→}
    99→
   100→/**
   101→ * Get DA (Digital Assistant) identity from settings.json
   102→ */
   103→export function getIdentity(): Identity {
   104→  const settings = loadSettings();
   105→
   106→  // Prefer settings.daidentity, fall back to env.DA for backward compat
   107→  const daidentity = settings.daidentity || {};
   108→  const envDA = settings.env?.DA;
   109→
   110→  return {
   111→    name: daidentity.name || envDA || DEFAULT_IDENTITY.name,
   112→    fullName: daidentity.fullName || daidentity.name || envDA || DEFAULT_IDENTITY.fullName,
   113→    displayName: daidentity.displayName || daidentity.name || envDA || DEFAULT_IDENTITY.displayName,
   114→    voiceId: daidentity.voiceId || DEFAULT_IDENTITY.voiceId,
   115→    color: daidentity.color || DEFAULT_IDENTITY.color,
   116→    voice: (daidentity as any).voice as VoiceProsody | undefined,
   117→    personality: (daidentity as any).personality as VoicePersonality | undefined,
   118→  };
   119→}
   120→
   121→/**
   122→ * Get Principal (human owner) identity from settings.json
   123→ */
   124→export function getPrincipal(): Principal {
   125→  const settings = loadSettings();
   126→
   127→  // Prefer settings.principal, fall back to env.PRINCIPAL for backward compat
   128→  const principal = settings.principal || {};
   129→  const envPrincipal = settings.env?.PRINCIPAL;
   130→
   131→  return {
   132→    name: principal.name || envPrincipal || DEFAULT_PRINCIPAL.name,
   133→    pronunciation: principal.pronunciation || DEFAULT_PRINCIPAL.pronunciation,
   134→    timezone: principal.timezone || DEFAULT_PRINCIPAL.timezone,
   135→  };
   136→}
   137→
   138→/**
   139→ * Clear cache (useful for testing or when settings.json changes)
   140→ */
   141→export function clearCache(): void {
   142→  cachedSettings = null;
   143→}
   144→
   145→/**
   146→ * Get just the DA name (convenience function)
   147→ */
   148→export function getDAName(): string {
   149→  return getIdentity().name;
   150→}
   151→
   152→/**
   153→ * Get just the Principal name (convenience function)
   154→ */
   155→export function getPrincipalName(): string {
   156→  return getPrincipal().name;
   157→}
   158→
   159→/**
   160→ * Get just the voice ID (convenience function)
   161→ */
   162→export function getVoiceId(): string {
   163→  return getIdentity().voiceId;
   164→}
   165→
   166→/**
   167→ * Get the full settings object (for advanced use)
   168→ */
   169→export function getSettings(): Settings {
   170→  return loadSettings();
   171→}
   172→
   173→/**
   174→ * Get the default identity (for documentation/testing)
   175→ */
   176→export function getDefaultIdentity(): Identity {
   177→  return { ...DEFAULT_IDENTITY };
   178→}
   179→
   180→/**
   181→ * Get the default principal (for documentation/testing)
   182→ */
   183→export function getDefaultPrincipal(): Principal {
   184→  return { ...DEFAULT_PRINCIPAL };
   185→}
   186→
   187→/**
   188→ * Get voice prosody settings (convenience function) - legacy ElevenLabs
   189→ */
   190→export function getVoiceProsody(): VoiceProsody | undefined {
   191→  return getIdentity().voice;
   192→}
   193→
   194→/**
   195→ * Get voice personality settings (convenience function) - Qwen3-TTS
   196→ */
   197→export function getVoicePersonality(): VoicePersonality | undefined {
   198→  return getIdentity().personality;
   199→}
