     1→/**
     2→ * change-detection.ts - Utilities for detecting PAI system changes
     3→ *
     4→ * Parses transcripts for file modification tool_use blocks and categorizes
     5→ * changes to determine if background integrity maintenance is needed.
     6→ */
     7→
     8→import { readFileSync, existsSync } from 'fs';
     9→import { join, relative, basename } from 'path';
    10→import { getPaiDir } from './paths';
    11→
    12→// ============================================================================
    13→// Types
    14→// ============================================================================
    15→
    16→export interface FileChange {
    17→  tool: 'Write' | 'Edit' | 'MultiEdit';
    18→  path: string;
    19→  category: ChangeCategory | null;
    20→  isPhilosophical: boolean;
    21→  isStructural: boolean;
    22→}
    23→
    24→export type ChangeCategory =
    25→  | 'skill'
    26→  | 'hook'
    27→  | 'workflow'
    28→  | 'config'
    29→  | 'core-system'
    30→  | 'memory-system'
    31→  | 'documentation';
    32→
    33→export type SignificanceLabel = 'trivial' | 'minor' | 'moderate' | 'major' | 'critical';
    34→
    35→export type ChangeType =
    36→  | 'skill_update'
    37→  | 'structure_change'
    38→  | 'doc_update'
    39→  | 'hook_update'
    40→  | 'workflow_update'
    41→  | 'config_update'
    42→  | 'tool_update'
    43→  | 'multi_area';
    44→
    45→export interface IntegrityState {
    46→  last_run: string;
    47→  last_changes_hash: string;
    48→  cooldown_until: string | null;
    49→}
    50→
    51→// ============================================================================
    52→// Path Constants
    53→// ============================================================================
    54→
    55→const PAI_DIR = getPaiDir();
    56→const STATE_FILE = join(PAI_DIR, 'MEMORY', 'STATE', 'integrity-state.json');
    57→
    58→// Paths that are excluded from integrity checks
    59→const EXCLUDED_PATHS = [
    60→  'MEMORY/WORK/',
    61→  'MEMORY/LEARNING/',
    62→  'MEMORY/STATE/',
    63→  'scratch/',
    64→  'Plans/',
    65→  'projects/',
    66→  '.git/',
    67→  'node_modules/',
    68→  'ShellSnapshots/',
    69→];
    70→
    71→// High-priority paths that always warrant documentation
    72→const HIGH_PRIORITY_PATHS = [
    73→  'skills/PAI/SYSTEM/',
    74→  'skills/PAI/USER/',
    75→  'PAISYSTEMARCHITECTURE.md',
    76→  'SKILLSYSTEM.md',
    77→  'MEMORYSYSTEM.md',
    78→  'THEHOOKSYSTEM.md',
    79→  'THEDELEGATIONSYSTEM.md',
    80→  'THENOTIFICATIONSYSTEM.md',
    81→  'settings.json',
    82→];
    83→
    84→// Philosophical/architectural patterns in paths
    85→const PHILOSOPHICAL_PATTERNS = [
    86→  /PAI\/SYSTEM\//i,
    87→  /PAI\/USER\//i,
    88→  /ARCHITECTURE/i,
    89→  /PRINCIPLES/i,
    90→  /FOUNDING/i,
    91→  /IDENTITY/i,
    92→];
    93→
    94→// Structural change patterns
    95→const STRUCTURAL_PATTERNS = [
    96→  /\/SKILL\.md$/i,           // Skill definitions
    97→  /\/Workflows\//i,          // Workflow routing
    98→  /settings\.json$/i,        // Configuration
    99→  /frontmatter/i,            // Metadata changes
   100→];
   101→
   102→// ============================================================================
   103→// Transcript Parsing
   104→// ============================================================================
   105→
   106→/**
   107→ * Parse tool_use blocks from a transcript that modify files.
   108→ * Extracts Write, Edit, and MultiEdit operations.
   109→ */
   110→export function parseToolUseBlocks(transcriptPath: string): FileChange[] {
   111→  try {
   112→    if (!existsSync(transcriptPath)) {
   113→      console.error('[ChangeDetection] Transcript not found:', transcriptPath);
   114→      return [];
   115→    }
   116→
   117→    const content = readFileSync(transcriptPath, 'utf-8');
   118→    const lines = content.trim().split('\n');
   119→    const changes: FileChange[] = [];
   120→    const seenPaths = new Set<string>();
   121→
   122→    for (const line of lines) {
   123→      if (!line.trim()) continue;
   124→
   125→      try {
   126→        const entry = JSON.parse(line);
   127→
   128→        // Look for assistant messages with tool_use
   129→        if (entry.type === 'assistant' && entry.message?.content) {
   130→          const contentArray = Array.isArray(entry.message.content)
   131→            ? entry.message.content
   132→            : [];
   133→
   134→          for (const block of contentArray) {
   135→            if (block.type !== 'tool_use') continue;
   136→
   137→            const toolName = block.name;
   138→            const input = block.input || {};
   139→
   140→            // Handle Write, Edit, MultiEdit tools
   141→            if (toolName === 'Write' && input.file_path) {
   142→              const path = normalizeToRelativePath(input.file_path);
   143→              if (!seenPaths.has(path)) {
   144→                seenPaths.add(path);
   145→                changes.push(createFileChange('Write', path));
   146→              }
   147→            } else if (toolName === 'Edit' && input.file_path) {
   148→              const path = normalizeToRelativePath(input.file_path);
   149→              if (!seenPaths.has(path)) {
   150→                seenPaths.add(path);
   151→                changes.push(createFileChange('Edit', path));
   152→              }
   153→            } else if (toolName === 'MultiEdit' && input.edits) {
   154→              for (const edit of input.edits) {
   155→                if (edit.file_path) {
   156→                  const path = normalizeToRelativePath(edit.file_path);
   157→                  if (!seenPaths.has(path)) {
   158→                    seenPaths.add(path);
   159→                    changes.push(createFileChange('Edit', path));
   160→                  }
   161→                }
   162→              }
   163→            }
   164→          }
   165→        }
   166→      } catch {
   167→        // Skip invalid JSON lines
   168→      }
   169→    }
   170→
   171→    return changes;
   172→  } catch (error) {
   173→    console.error('[ChangeDetection] Error parsing transcript:', error);
   174→    return [];
   175→  }
   176→}
   177→
   178→/**
   179→ * Normalize an absolute path to relative (to PAI_DIR).
   180→ */
   181→function normalizeToRelativePath(absolutePath: string): string {
   182→  if (absolutePath.startsWith(PAI_DIR)) {
   183→    return relative(PAI_DIR, absolutePath);
   184→  }
   185→  return absolutePath;
   186→}
   187→
   188→/**
   189→ * Create a FileChange object with categorization.
   190→ */
   191→function createFileChange(tool: 'Write' | 'Edit', path: string): FileChange {
   192→  return {
   193→    tool,
   194→    path,
   195→    category: categorizeChange(path),
   196→    isPhilosophical: isPhilosophicalPath(path),
   197→    isStructural: isStructuralPath(path),
   198→  };
   199→}
   200→
   201→// ============================================================================
   202→// Change Categorization
   203→// ============================================================================
   204→
   205→/**
   206→ * Categorize a file path by its location in the PAI system.
   207→ */
   208→export function categorizeChange(path: string): ChangeCategory | null {
   209→  // Check exclusions first
   210→  for (const excluded of EXCLUDED_PATHS) {
   211→    if (path.includes(excluded)) {
   212→      return null;
   213→    }
   214→  }
   215→
   216→  // Check if path is within PAI directory
   217→  const absolutePath = path.startsWith('/') ? path : join(PAI_DIR, path);
   218→  if (!absolutePath.startsWith(PAI_DIR)) {
   219→    return null;
   220→  }
   221→
   222→  // Categorize by path pattern
   223→  if (path.includes('skills/')) {
   224→    if (path.includes('/Workflows/')) return 'workflow';
   225→    if (path.includes('PAI/SYSTEM/')) return 'core-system';
   226→    return 'skill';
   227→  }
   228→
   229→  if (path.includes('hooks/')) return 'hook';
   230→  if (path.includes('MEMORY/PAISYSTEMUPDATES/')) return 'documentation';
   231→  if (path.includes('MEMORY/')) return 'memory-system';
   232→  if (path.endsWith('settings.json')) return 'config';
   233→  if (path.endsWith('.md') && !path.includes('WORK/')) return 'documentation';
   234→
   235→  return null;
   236→}
   237→
   238→/**
   239→ * Check if a path represents philosophical/architectural content.
   240→ */
   241→function isPhilosophicalPath(path: string): boolean {
   242→  for (const pattern of PHILOSOPHICAL_PATTERNS) {
   243→    if (pattern.test(path)) return true;
   244→  }
   245→  for (const highPriority of HIGH_PRIORITY_PATHS) {
   246→    if (path.includes(highPriority)) return true;
   247→  }
   248→  return false;
   249→}
   250→
   251→/**
   252→ * Check if a path represents structural content (SKILL.md, workflows, config).
   253→ */
   254→function isStructuralPath(path: string): boolean {
   255→  for (const pattern of STRUCTURAL_PATTERNS) {
   256→    if (pattern.test(path)) return true;
   257→  }
   258→  return false;
   259→}
   260→
   261→// ============================================================================
   262→// Significance Detection
   263→// ============================================================================
   264→
   265→/**
   266→ * Determine if changes are significant enough to warrant background integrity check.
   267→ */
   268→export function isSignificantChange(changes: FileChange[]): boolean {
   269→  // Filter to only PAI system changes
   270→  const systemChanges = changes.filter(c => c.category !== null);
   271→
   272→  if (systemChanges.length === 0) return false;
   273→
   274→  // Always significant if philosophical or structural changes
   275→  if (systemChanges.some(c => c.isPhilosophical || c.isStructural)) {
   276→    return true;
   277→  }
   278→
   279→  // Significant if multiple files in same domain
   280→  const categories = new Set(systemChanges.map(c => c.category));
   281→  if (categories.size >= 1 && systemChanges.length >= 2) {
   282→    return true;
   283→  }
   284→
   285→  // Significant if any skill, hook, or core-system change
   286→  const importantCategories: ChangeCategory[] = ['skill', 'hook', 'core-system', 'workflow'];
   287→  if (systemChanges.some(c => importantCategories.includes(c.category!))) {
   288→    return true;
   289→  }
   290→
   291→  return false;
   292→}
   293→
   294→/**
   295→ * Check if changes warrant documentation.
   296→ * UPDATED: Lower thresholds for more granular, frequent documentation.
   297→ * Philosophy: File system is cheap, more signal is valuable.
   298→ */
   299→export function shouldDocumentChanges(changes: FileChange[]): boolean {
   300→  const systemChanges = changes.filter(c => c.category !== null);
   301→
   302→  // No changes to document
   303→  if (systemChanges.length === 0) return false;
   304→
   305→  // Always document philosophical or structural changes
   306→  if (systemChanges.some(c => c.isPhilosophical || c.isStructural)) {
   307→    return true;
   308→  }
   309→
   310→  // Document ANY skill, hook, workflow, core-system, or config change
   311→  const importantCategories: ChangeCategory[] = ['skill', 'hook', 'workflow', 'core-system', 'config'];
   312→  if (systemChanges.some(c => c.category && importantCategories.includes(c.category))) {
   313→    return true;
   314→  }
   315→
   316→  // Document if 2+ files changed (lowered from 3+)
   317→  if (systemChanges.length >= 2) {
   318→    return true;
   319→  }
   320→
   321→  // Document new file creation in system areas
   322→  const newFiles = systemChanges.filter(c => c.tool === 'Write');
   323→  if (newFiles.length > 0) return true;
   324→
   325→  // Document any tool file changes (.ts in Tools/)
   326→  if (systemChanges.some(c => c.path.includes('/Tools/') && c.path.endsWith('.ts'))) {
   327→    return true;
   328→  }
   329→
   330→  return false;
   331→}
   332→
   333→// ============================================================================
   334→// Throttling
   335→// ============================================================================
   336→
   337→// Reduced from 5 to 2 minutes for more frequent documentation updates
   338→const COOLDOWN_MINUTES = 2;
   339→
   340→/**
   341→ * Read the current integrity state.
   342→ */
   343→export function readIntegrityState(): IntegrityState | null {
   344→  try {
   345→    if (!existsSync(STATE_FILE)) return null;
   346→    const content = readFileSync(STATE_FILE, 'utf-8');
   347→    return JSON.parse(content);
   348→  } catch {
   349→    return null;
   350→  }
   351→}
   352→
   353→/**
   354→ * Check if we're within the cooldown period.
   355→ */
   356→export function isInCooldown(): boolean {
   357→  const state = readIntegrityState();
   358→  if (!state?.cooldown_until) return false;
   359→
   360→  const cooldownUntil = new Date(state.cooldown_until);
   361→  return new Date() < cooldownUntil;
   362→}
   363→
   364→/**
   365→ * Generate a hash of changes for deduplication.
   366→ */
   367→export function hashChanges(changes: FileChange[]): string {
   368→  const sorted = changes
   369→    .map(c => `${c.tool}:${c.path}`)
   370→    .sort()
   371→    .join('|');
   372→
   373→  // Simple hash
   374→  let hash = 0;
   375→  for (let i = 0; i < sorted.length; i++) {
   376→    const char = sorted.charCodeAt(i);
   377→    hash = ((hash << 5) - hash) + char;
   378→    hash = hash & hash;
   379→  }
   380→  return hash.toString(16);
   381→}
   382→
   383→/**
   384→ * Check if changes are duplicates of the last run.
   385→ */
   386→export function isDuplicateRun(changes: FileChange[]): boolean {
   387→  const state = readIntegrityState();
   388→  if (!state?.last_changes_hash) return false;
   389→
   390→  const currentHash = hashChanges(changes);
   391→  return currentHash === state.last_changes_hash;
   392→}
   393→
   394→/**
   395→ * Get the cooldown end time.
   396→ */
   397→export function getCooldownEndTime(): string {
   398→  const now = new Date();
   399→  now.setMinutes(now.getMinutes() + COOLDOWN_MINUTES);
   400→  return now.toISOString();
   401→}
   402→
   403→// ============================================================================
   404→// Significance and Change Type Determination
   405→// ============================================================================
   406→
   407→/**
   408→ * Determine the significance label based on change characteristics.
   409→ */
   410→export function determineSignificance(changes: FileChange[]): SignificanceLabel {
   411→  const count = changes.length;
   412→  const hasStructural = changes.some(c => c.isStructural);
   413→  const hasPhilosophical = changes.some(c => c.isPhilosophical);
   414→  const hasNewFiles = changes.some(c => c.tool === 'Write');
   415→
   416→  const categories = new Set(changes.map(c => c.category).filter(Boolean));
   417→  const hasCoreSystem = changes.some(c => c.category === 'core-system');
   418→  const hasHooks = changes.some(c => c.category === 'hook');
   419→  const hasSkills = changes.some(c => c.category === 'skill');
   420→
   421→  // Critical: breaking changes, major restructuring
   422→  if (hasStructural && hasPhilosophical && count >= 5) {
   423→    return 'critical';
   424→  }
   425→
   426→  // Major: new skills/workflows, architectural decisions
   427→  if (hasNewFiles && (hasStructural || hasPhilosophical)) {
   428→    return 'major';
   429→  }
   430→  if (hasCoreSystem || (categories.size >= 3)) {
   431→    return 'major';
   432→  }
   433→  if (hasHooks && count >= 3) {
   434→    return 'major';
   435→  }
   436→
   437→  // Moderate: multi-file updates, small features
   438→  if (count >= 3 || categories.size >= 2) {
   439→    return 'moderate';
   440→  }
   441→  if (hasSkills && count >= 2) {
   442→    return 'moderate';
   443→  }
   444→
   445→  // Minor: single file doc updates
   446→  if (count === 1 && !hasStructural && !hasPhilosophical) {
   447→    return 'minor';
   448→  }
   449→
   450→  // Trivial: only if very small doc changes
   451→  if (count === 1 && changes[0].category === 'documentation') {
   452→    return 'trivial';
   453→  }
   454→
   455→  return 'minor';
   456→}
   457→
   458→/**
   459→ * Determine the change type based on affected files.
   460→ */
   461→export function inferChangeType(changes: FileChange[]): ChangeType {
   462→  const categories = changes.map(c => c.category).filter(Boolean);
   463→  const uniqueCategories = new Set(categories);
   464→
   465→  // Multi-area if touching 3+ categories
   466→  if (uniqueCategories.size >= 3) {
   467→    return 'multi_area';
   468→  }
   469→
   470→  // Single category cases
   471→  if (uniqueCategories.size === 1) {
   472→    const cat = [...uniqueCategories][0];
   473→    switch (cat) {
   474→      case 'skill': return changes.some(c => c.isStructural) ? 'structure_change' : 'skill_update';
   475→      case 'hook': return 'hook_update';
   476→      case 'workflow': return 'workflow_update';
   477→      case 'config': return 'config_update';
   478→      case 'core-system': return 'structure_change';
   479→      case 'documentation': return 'doc_update';
   480→      default: return 'skill_update';
   481→    }
   482→  }
   483→
   484→  // Two categories - pick the more significant one
   485→  if (uniqueCategories.has('hook')) return 'hook_update';
   486→  if (uniqueCategories.has('skill')) return 'skill_update';
   487→  if (uniqueCategories.has('workflow')) return 'workflow_update';
   488→  if (uniqueCategories.has('config')) return 'config_update';
   489→
   490→  return 'multi_area';
   491→}
   492→
   493→/**
   494→ * Generate a descriptive 4-8 word title based on the changes.
   495→ */
   496→export function generateDescriptiveTitle(changes: FileChange[]): string {
   497→  const paths = changes.map(c => c.path);
   498→
   499→  // Extract skill names
   500→  const skillNames = new Set<string>();
   501→  for (const p of paths) {
   502→    const match = p.match(/skills\/([^/]+)\//);
   503→    if (match && match[1] !== 'PAI') skillNames.add(match[1]);
   504→  }
   505→
   506→  // Detect file types
   507→  const hasSkillMd = paths.some(p => p.endsWith('SKILL.md'));
   508→  const hasWorkflows = paths.some(p => p.includes('/Workflows/'));
   509→  const hasTools = paths.some(p => p.includes('/Tools/') && p.endsWith('.ts'));
   510→  const hasHooks = paths.some(p => p.includes('hooks/'));
   511→  const hasConfig = paths.some(p => p.endsWith('settings.json'));
   512→  const hasCoreSystem = paths.some(p => p.includes('PAI/SYSTEM/'));
   513→  const hasCoreUser = paths.some(p => p.includes('PAI/USER/'));
   514→
   515→  let title = '';
   516→
   517→  // Single skill update
   518→  if (skillNames.size === 1) {
   519→    const skill = [...skillNames][0];
   520→    if (hasSkillMd) {
   521→      title = `${skill} Skill Definition Update`;
   522→    } else if (hasWorkflows) {
   523→      const workflowNames = paths
   524→        .filter(p => p.includes('/Workflows/'))
   525→        .map(p => basename(p, '.md'));
   526→      if (workflowNames.length === 1) {
   527→        title = `${skill} ${workflowNames[0]} Workflow Update`;
   528→      } else {
   529→        title = `${skill} Workflows Updated`;
   530→      }
   531→    } else if (hasTools) {
   532→      const toolNames = paths
   533→        .filter(p => p.includes('/Tools/'))
   534→        .map(p => basename(p, '.ts'));
   535→      if (toolNames.length === 1) {
   536→        title = `${skill} ${toolNames[0]} Tool Update`;
   537→      } else {
   538→        title = `${skill} Tools Updated`;
   539→      }
   540→    } else {
   541→      title = `${skill} Skill Files Updated`;
   542→    }
   543→  }
   544→  // Multiple skills
   545→  else if (skillNames.size > 1 && skillNames.size <= 3) {
   546→    const skills = [...skillNames].slice(0, 3).join(' and ');
   547→    title = `${skills} Skills Updated`;
   548→  }
   549→  // Hook changes
   550→  else if (hasHooks) {
   551→    const hookNames = paths
   552→      .filter(p => p.includes('hooks/'))
   553→      .map(p => basename(p, '.ts').replace('.hook', ''));
   554→    if (hookNames.length === 1) {
   555→      title = `${hookNames[0]} Hook Updated`;
   556→    } else if (hookNames.length <= 3) {
   557→      title = `${hookNames.slice(0, 3).join(', ')} Hooks Updated`;
   558→    } else {
   559→      title = `Hook System Updates`;
   560→    }
   561→  }
   562→  // Config changes
   563→  else if (hasConfig) {
   564→    title = 'System Configuration Updated';
   565→  }
   566→  // Core system changes
   567→  else if (hasCoreSystem) {
   568→    const docNames = paths
   569→      .filter(p => p.includes('PAI/SYSTEM/'))
   570→      .map(p => basename(p, '.md'));
   571→    if (docNames.length === 1) {
   572→      title = `${docNames[0]} Documentation Updated`;
   573→    } else {
   574→      title = 'PAI System Documentation Updated';
   575→    }
   576→  }
   577→  // Core user changes
   578→  else if (hasCoreUser) {
   579→    const docNames = paths
   580→      .filter(p => p.includes('PAI/USER/'))
   581→      .map(p => basename(p, '.md'));
   582→    if (docNames.length === 1) {
   583→      title = `${docNames[0]} User Config Updated`;
   584→    } else {
   585→      title = 'User Configuration Updated';
   586→    }
   587→  }
   588→  // Fallback
   589→  else {
   590→    const categories = new Set(changes.map(c => c.category).filter(Boolean));
   591→    if (categories.size === 1) {
   592→      const cat = [...categories][0];
   593→      title = `${capitalize(cat || 'System')} Updates Applied`;
   594→    } else {
   595→      title = 'Multi-Area System Updates Applied';
   596→    }
   597→  }
   598→
   599→  // Ensure 4-8 words
   600→  const words = title.split(/\s+/);
   601→  if (words.length < 4) {
   602→    title = `PAI ${title}`;
   603→  } else if (words.length > 8) {
   604→    title = words.slice(0, 8).join(' ');
   605→  }
   606→
   607→  return title;
   608→}
   609→
   610→function capitalize(s: string): string {
   611→  return s.charAt(0).toUpperCase() + s.slice(1);
   612→}
