     1→/**
     2→ * Notification Service
     3→ * Multi-channel notification system for PAI infrastructure
     4→ *
     5→ * Channels:
     6→ * - ntfy.sh: Mobile push notifications
     7→ * - Discord: Team/server notifications (optional)
     8→ * - Desktop: Native macOS notifications
     9→ *
    10→ * Design principles:
    11→ * - Async, non-blocking (fire-and-forget)
    12→ * - Fail gracefully (never block hook execution)
    13→ * - Priority-based routing
    14→ * - Conservative defaults (avoid notification fatigue)
    15→ */
    16→
    17→import { readFileSync, existsSync, writeFileSync, mkdirSync } from 'fs';
    18→import { join } from 'path';
    19→import { homedir } from 'os';
    20→import { getIdentity } from './identity';
    21→
    22→// ============================================================================
    23→// Types
    24→// ============================================================================
    25→
    26→export type NotificationPriority = 'min' | 'low' | 'default' | 'high' | 'urgent';
    27→
    28→export type NotificationEvent =
    29→  | 'taskComplete'      // Normal task completion
    30→  | 'longTask'          // Task that took >5 minutes
    31→  | 'backgroundAgent'   // Background agent completed
    32→  | 'error'             // Error occurred
    33→  | 'security';         // Security alert
    34→
    35→export interface NotificationOptions {
    36→  title?: string;
    37→  priority?: NotificationPriority;
    38→  tags?: string[];        // ntfy emoji tags like 'robot', 'white_check_mark'
    39→  click?: string;         // URL to open on click
    40→  actions?: Array<{       // ntfy action buttons
    41→    action: 'view' | 'http';
    42→    label: string;
    43→    url: string;
    44→  }>;
    45→}
    46→
    47→export interface NotificationConfig {
    48→  ntfy: {
    49→    enabled: boolean;
    50→    topic: string;
    51→    server: string;
    52→  };
    53→  discord: {
    54→    enabled: boolean;
    55→    webhook: string;
    56→  };
    57→  twilio: {
    58→    enabled: boolean;
    59→    toNumber: string;  // User's phone number for SMS alerts
    60→  };
    61→  thresholds: {
    62→    longTaskMinutes: number;
    63→  };
    64→  routing: {
    65→    [key in NotificationEvent]: ('ntfy' | 'discord' | 'desktop' | 'sms')[];
    66→  };
    67→}
    68→
    69→// ============================================================================
    70→// Configuration
    71→// ============================================================================
    72→
    73→const DEFAULT_CONFIG: NotificationConfig = {
    74→  ntfy: {
    75→    enabled: false,  // Disabled by default - configure in settings.json
    76→    topic: '',       // Required: set in settings.json notifications.ntfy.topic
    77→    server: 'ntfy.sh'
    78→  },
    79→  discord: {
    80→    enabled: false,
    81→    webhook: ''
    82→  },
    83→  twilio: {
    84→    enabled: false,
    85→    toNumber: ''
    86→  },
    87→  thresholds: {
    88→    longTaskMinutes: 5
    89→  },
    90→  routing: {
    91→    taskComplete: [],                    // Voice only (existing behavior)
    92→    longTask: ['ntfy'],                  // Push for long tasks
    93→    backgroundAgent: ['ntfy'],           // Push for background completions
    94→    error: ['ntfy', 'discord'],          // Multiple channels for errors
    95→    security: ['ntfy', 'discord', 'sms'] // All channels for security
    96→  }
    97→};
    98→
    99→/**
   100→ * Expand ${VAR} patterns in a string using environment variables
   101→ */
   102→function expandEnvVars(content: string): string {
   103→  return content.replace(/\$\{(\w+)\}/g, (_, key) => process.env[key] || '');
   104→}
   105→
   106→/**
   107→ * Load notification config from settings.json
   108→ */
   109→export function getNotificationConfig(): NotificationConfig {
   110→  try {
   111→    const paiDir = process.env.PAI_DIR || join(homedir(), '.claude');
   112→    const settingsPath = join(paiDir, 'settings.json');
   113→
   114→    if (existsSync(settingsPath)) {
   115→      const rawContent = readFileSync(settingsPath, 'utf-8');
   116→      const expandedContent = expandEnvVars(rawContent);
   117→      const settings = JSON.parse(expandedContent);
   118→      if (settings.notifications) {
   119→        return {
   120→          ...DEFAULT_CONFIG,
   121→          ...settings.notifications,
   122→          ntfy: { ...DEFAULT_CONFIG.ntfy, ...settings.notifications?.ntfy },
   123→          discord: { ...DEFAULT_CONFIG.discord, ...settings.notifications?.discord },
   124→          twilio: { ...DEFAULT_CONFIG.twilio, ...settings.notifications?.twilio },
   125→          thresholds: { ...DEFAULT_CONFIG.thresholds, ...settings.notifications?.thresholds },
   126→          routing: { ...DEFAULT_CONFIG.routing, ...settings.notifications?.routing }
   127→        };
   128→      }
   129→    }
   130→  } catch (error) {
   131→    // Fail gracefully, use defaults
   132→    console.error('Failed to load notification config:', error);
   133→  }
   134→
   135→  return DEFAULT_CONFIG;
   136→}
   137→
   138→// ============================================================================
   139→// Session Timing
   140→// ============================================================================
   141→
   142→const SESSION_START_FILE = '/tmp/pai-session-start.txt';
   143→
   144→/**
   145→ * Record session start time (call from SessionStart hook)
   146→ */
   147→export function recordSessionStart(): void {
   148→  try {
   149→    writeFileSync(SESSION_START_FILE, Date.now().toString());
   150→  } catch (error) {
   151→    // Fail gracefully
   152→  }
   153→}
   154→
   155→/**
   156→ * Get session duration in minutes
   157→ */
   158→export function getSessionDurationMinutes(): number {
   159→  try {
   160→    if (existsSync(SESSION_START_FILE)) {
   161→      const startTime = parseInt(readFileSync(SESSION_START_FILE, 'utf-8'));
   162→      const duration = (Date.now() - startTime) / 1000 / 60; // minutes
   163→      return duration;
   164→    }
   165→  } catch (error) {
   166→    // Fail gracefully
   167→  }
   168→  return 0;
   169→}
   170→
   171→/**
   172→ * Determine if current task is "long running" based on threshold
   173→ */
   174→export function isLongRunningTask(): boolean {
   175→  const config = getNotificationConfig();
   176→  const duration = getSessionDurationMinutes();
   177→  return duration >= config.thresholds.longTaskMinutes;
   178→}
   179→
   180→// ============================================================================
   181→// Channel Implementations
   182→// ============================================================================
   183→
   184→/**
   185→ * Send push notification via ntfy.sh
   186→ */
   187→export async function sendPush(
   188→  message: string,
   189→  options: NotificationOptions = {}
   190→): Promise<boolean> {
   191→  const config = getNotificationConfig();
   192→
   193→  if (!config.ntfy.enabled || !config.ntfy.topic) {
   194→    return false;
   195→  }
   196→
   197→  try {
   198→    const url = `https://${config.ntfy.server}/${config.ntfy.topic}`;
   199→
   200→    const headers: Record<string, string> = {
   201→      'Content-Type': 'text/plain',
   202→    };
   203→
   204→    if (options.title) {
   205→      headers['Title'] = options.title;
   206→    }
   207→
   208→    if (options.priority) {
   209→      // ntfy uses numeric priorities: 1 (min) to 5 (max)
   210→      const priorityMap: Record<NotificationPriority, string> = {
   211→        'min': '1',
   212→        'low': '2',
   213→        'default': '3',
   214→        'high': '4',
   215→        'urgent': '5'
   216→      };
   217→      headers['Priority'] = priorityMap[options.priority] || '3';
   218→    }
   219→
   220→    if (options.tags && options.tags.length > 0) {
   221→      headers['Tags'] = options.tags.join(',');
   222→    }
   223→
   224→    if (options.click) {
   225→      headers['Click'] = options.click;
   226→    }
   227→
   228→    if (options.actions && options.actions.length > 0) {
   229→      headers['Actions'] = options.actions
   230→        .map(a => `${a.action}, ${a.label}, ${a.url}`)
   231→        .join('; ');
   232→    }
   233→
   234→    const response = await fetch(url, {
   235→      method: 'POST',
   236→      headers,
   237→      body: message
   238→    });
   239→
   240→    return response.ok;
   241→  } catch (error) {
   242→    // Fail silently - don't block hook execution
   243→    console.error('ntfy send failed:', error);
   244→    return false;
   245→  }
   246→}
   247→
   248→/**
   249→ * Send notification to Discord webhook
   250→ */
   251→export async function sendDiscord(
   252→  message: string,
   253→  options: {
   254→    title?: string;
   255→    description?: string;
   256→    color?: number;       // Embed color (decimal)
   257→    fields?: Array<{ name: string; value: string; inline?: boolean }>;
   258→  } = {}
   259→): Promise<boolean> {
   260→  const config = getNotificationConfig();
   261→
   262→  if (!config.discord.enabled || !config.discord.webhook) {
   263→    return false;
   264→  }
   265→
   266→  try {
   267→    const payload: any = {};
   268→
   269→    if (options.title || options.description || options.fields) {
   270→      // Use embed for rich messages
   271→      payload.embeds = [{
   272→        title: options.title,
   273→        description: options.description || message,
   274→        color: options.color || 0x7289da, // Discord blurple
   275→        fields: options.fields,
   276→        timestamp: new Date().toISOString()
   277→      }];
   278→    } else {
   279→      // Simple text message
   280→      payload.content = message;
   281→    }
   282→
   283→    const response = await fetch(config.discord.webhook, {
   284→      method: 'POST',
   285→      headers: { 'Content-Type': 'application/json' },
   286→      body: JSON.stringify(payload)
   287→    });
   288→
   289→    return response.ok;
   290→  } catch (error) {
   291→    console.error('Discord send failed:', error);
   292→    return false;
   293→  }
   294→}
   295→
   296→/**
   297→ * Send native macOS desktop notification
   298→ */
   299→export async function sendDesktop(
   300→  title: string,
   301→  message: string,
   302→  options: {
   303→    sound?: string;       // Sound name (e.g., 'Glass', 'Ping')
   304→    subtitle?: string;
   305→  } = {}
   306→): Promise<boolean> {
   307→  try {
   308→    const soundPart = options.sound ? ` sound name "${options.sound}"` : '';
   309→    const subtitlePart = options.subtitle ? ` subtitle "${options.subtitle}"` : '';
   310→
   311→    const script = `display notification "${message}" with title "${title}"${subtitlePart}${soundPart}`;
   312→
   313→    const proc = Bun.spawn(['osascript', '-e', script]);
   314→    await proc.exited;
   315→
   316→    return proc.exitCode === 0;
   317→  } catch (error) {
   318→    console.error('Desktop notification failed:', error);
   319→    return false;
   320→  }
   321→}
   322→
   323→/**
   324→ * Send SMS via Twilio
   325→ * Uses curl for reliability (Bun fetch has connection issues with Twilio)
   326→ */
   327→export async function sendSMS(message: string): Promise<boolean> {
   328→  const config = getNotificationConfig();
   329→
   330→  if (!config.twilio.enabled || !config.twilio.toNumber) {
   331→    return false;
   332→  }
   333→
   334→  const accountSid = process.env.TWILIO_ACCOUNT_SID;
   335→  const authToken = process.env.TWILIO_AUTH_TOKEN;
   336→
   337→  if (!accountSid || !authToken) {
   338→    console.error('Twilio credentials not found in environment');
   339→    return false;
   340→  }
   341→
   342→  try {
   343→    const fromNumber = process.env.TWILIO_FROM_NUMBER;
   344→    if (!fromNumber) {
   345→      console.error('TWILIO_FROM_NUMBER not set in environment');
   346→      return false;
   347→    }
   348→    const DA_NAME = getIdentity().name;
   349→    const body = `[${DA_NAME}] ${message}`.substring(0, 160); // SMS limit
   350→
   351→    // Use curl for reliability
   352→    const proc = Bun.spawn([
   353→      'curl', '-s', '-X', 'POST',
   354→      `https://api.twilio.com/2010-04-01/Accounts/${accountSid}/Messages.json`,
   355→      '-u', `${accountSid}:${authToken}`,
   356→      '-d', `To=${config.twilio.toNumber}`,
   357→      '-d', `From=${fromNumber}`,
   358→      '-d', `Body=${body}`
   359→    ]);
   360→
   361→    await proc.exited;
   362→    return proc.exitCode === 0;
   363→  } catch (error) {
   364→    console.error('SMS send failed:', error);
   365→    return false;
   366→  }
   367→}
   368→
   369→// ============================================================================
   370→// Smart Router
   371→// ============================================================================
   372→
   373→/**
   374→ * Send notification through appropriate channels based on event type
   375→ * This is the main entry point for notifications
   376→ */
   377→export async function notify(
   378→  event: NotificationEvent,
   379→  message: string,
   380→  options: NotificationOptions = {}
   381→): Promise<void> {
   382→  const config = getNotificationConfig();
   383→  const channels = config.routing[event] || [];
   384→
   385→  // Fire all notifications in parallel, don't wait for completion
   386→  const promises: Promise<boolean>[] = [];
   387→
   388→  for (const channel of channels) {
   389→    switch (channel) {
   390→      case 'ntfy':
   391→        promises.push(sendPush(message, {
   392→          title: options.title || getDefaultTitle(event),
   393→          priority: options.priority || getDefaultPriority(event),
   394→          tags: options.tags || getDefaultTags(event),
   395→          ...options
   396→        }));
   397→        break;
   398→
   399→      case 'discord':
   400→        promises.push(sendDiscord(message, {
   401→          title: options.title || getDefaultTitle(event),
   402→          color: getDiscordColor(event)
   403→        }));
   404→        break;
   405→
   406→      case 'desktop':
   407→        promises.push(sendDesktop(
   408→          options.title || getDefaultTitle(event),
   409→          message,
   410→          { sound: event === 'error' || event === 'security' ? 'Basso' : 'Glass' }
   411→        ));
   412→        break;
   413→
   414→      case 'sms':
   415→        promises.push(sendSMS(message));
   416→        break;
   417→    }
   418→  }
   419→
   420→  // Fire and forget - don't await
   421→  Promise.all(promises).catch(() => {
   422→    // Silently ignore failures
   423→  });
   424→}
   425→
   426→/**
   427→ * Convenience function for task completion with duration check
   428→ */
   429→export async function notifyTaskComplete(message: string, options: NotificationOptions = {}): Promise<void> {
   430→  const event: NotificationEvent = isLongRunningTask() ? 'longTask' : 'taskComplete';
   431→  await notify(event, message, options);
   432→}
   433→
   434→/**
   435→ * Convenience function for background agent completion
   436→ */
   437→export async function notifyBackgroundAgent(
   438→  agentType: string,
   439→  message: string,
   440→  options: NotificationOptions = {}
   441→): Promise<void> {
   442→  await notify('backgroundAgent', message, {
   443→    title: `${agentType} Agent Complete`,
   444→    tags: ['robot', 'white_check_mark'],
   445→    ...options
   446→  });
   447→}
   448→
   449→/**
   450→ * Convenience function for error notifications
   451→ */
   452→export async function notifyError(message: string, options: NotificationOptions = {}): Promise<void> {
   453→  await notify('error', message, {
   454→    priority: 'high',
   455→    tags: ['warning', 'x'],
   456→    ...options
   457→  });
   458→}
   459→
   460→// ============================================================================
   461→// Helpers
   462→// ============================================================================
   463→
   464→function getDefaultTitle(event: NotificationEvent): string {
   465→  const DA_NAME = getIdentity().name;
   466→  const titles: Record<NotificationEvent, string> = {
   467→    taskComplete: DA_NAME,
   468→    longTask: `${DA_NAME} - Task Complete`,
   469→    backgroundAgent: `${DA_NAME} - Agent Complete`,
   470→    error: `${DA_NAME} - Error`,
   471→    security: `${DA_NAME} - Security Alert`
   472→  };
   473→  return titles[event];
   474→}
   475→
   476→function getDefaultPriority(event: NotificationEvent): NotificationPriority {
   477→  const priorities: Record<NotificationEvent, NotificationPriority> = {
   478→    taskComplete: 'default',
   479→    longTask: 'default',
   480→    backgroundAgent: 'default',
   481→    error: 'high',
   482→    security: 'urgent'
   483→  };
   484→  return priorities[event];
   485→}
   486→
   487→function getDefaultTags(event: NotificationEvent): string[] {
   488→  const tags: Record<NotificationEvent, string[]> = {
   489→    taskComplete: ['white_check_mark'],
   490→    longTask: ['hourglass', 'white_check_mark'],
   491→    backgroundAgent: ['robot', 'white_check_mark'],
   492→    error: ['warning', 'x'],
   493→    security: ['rotating_light', 'lock']
   494→  };
   495→  return tags[event];
   496→}
   497→
   498→function getDiscordColor(event: NotificationEvent): number {
   499→  const colors: Record<NotificationEvent, number> = {
   500→    taskComplete: 0x57f287,   // Green
   501→    longTask: 0x57f287,       // Green
   502→    backgroundAgent: 0x5865f2, // Blurple
   503→    error: 0xed4245,          // Red
   504→    security: 0xfee75c        // Yellow
   505→  };
   506→  return colors[event];
   507→}
